SELECT id, user_id, user_name, user_phone, user_room, order_no, shop_name, shop_phone, total_amount, delivery_fee, actual_amount, order_status, payment_method, payment_time, delivery_time, actual_delivery_time, delivery_address, remark, cancel_reason, reservation_id, complaint_id, create_by, create_time, update_by, update_time
FROM community_takeout
WHERE user_id = #{userId}
  AND user_name LIKE CONCAT('%', #{userName}, '%')
  AND user_phone = #{userPhone}
  AND user_room = #{userRoom}
  AND order_no = #{orderNo}
  AND shop_name LIKE CONCAT('%', #{shopName}, '%')
  AND shop_phone = #{shopPhone}
  AND total_amount = #{totalAmount}
  AND delivery_fee = #{deliveryFee}
  AND actual_amount = #{actualAmount}
  AND order_status = #{orderStatus}
  AND payment_method = #{paymentMethod}
  AND payment_time = #{paymentTime}
  AND delivery_time = #{deliveryTime}
  AND actual_delivery_time = #{actualDeliveryTime}
  AND delivery_address = #{deliveryAddress}
  AND cancel_reason = #{cancelReason}
  AND reservation_id = #{reservationId}
  AND complaint_id = #{complaintId}

SELECT id, user_id, user_name, user_phone, user_room, order_no, shop_name, shop_phone, total_amount, delivery_fee, actual_amount, order_status, payment_method, payment_time, delivery_time, actual_delivery_time, delivery_address, remark, cancel_reason, reservation_id, complaint_id, create_by, create_time, update_by, update_time
FROM community_takeout
WHERE id = #{id}
